def ingest_feedback(feedback_data):
    """Ingest user feedback into Elasticsearch."""
    try:
        for feedback in feedback_data:
            document = {
                "user_id": feedback['user_id'],
                "feedback": feedback['feedback'],
                "timestamp": datetime.utcnow(),
                "platform": feedback['platform']
            }
            response = es.index(index=ELASTICSEARCH_INDEX, document=document)
            logger.info(f"Document indexed with ID: {response['_id']}")
    except Exception as e:
        logger.error(f"Error ingesting feedback: {str(e)}")

def fetch_feedback_from_source(api_url):
    """Fetch feedback from a given API source."""
    try:
        response = requests.get(api_url)
        response.raise_for_status()
        return response.json()
    except requests.RequestException as e:
        logger.error(f"Error fetching feedback data: {str(e)}")
        return []

def main():
    # Example API endpoint for fetching feedback
    api_url = "https://api.example.com/feedback"

    # Fetch feedback data
    feedback_data = fetch_feedback_from_source(api_url)

    # Ingest feedback into Elasticsearch
    ingest_feedback(feedback_data)

