const complianceReducer = (state = initialState, action) => {
  switch (action.type) {
    case 'SET_COMPLIANCE_DATA':
      return { ...state, complianceData: action.payload };
    case 'ADD_ALERT':
      return { ...state, alerts: [...state.alerts, action.payload] };
    default:
      return state;
  }
};

export default complianceReducer;

