const nlp = require('compromise'); // Assuming compromise is used for NLP

/**
 * Parses a legal document to extract compliance-related data.
 * @param {string} document - The legal document text.
 * @returns {Object} - Extracted data from the document.
 */
function parseDocument(document) {
    if (!document || typeof document !== 'string') {
        throw new Error('Invalid document format');
    }

    const parsedData = {};
    const doc = nlp(document);

    parsedData.terms = doc.match('#Terms').out('array');
    parsedData.policy = doc.match('#Policy').out('array');
    parsedData.ageVerification = doc.has('#AgeVerification');

    return parsedData;
}

module.exports = parseDocument;

