/**
 * Generates compliance alerts based on parsed data.
 * @param {Object} parsedData - Data extracted from legal documents.
 * @returns {Array} - List of alerts.
 */
function generateAlerts(parsedData) {
    const alerts = [];

    if (!parsedData.ageVerification) {
        alerts.push('Missing age verification requirement.');
    }
    if (!parsedData.terms.length) {
        alerts.push('No terms found.');
    }
    if (!parsedData.policy.length) {
        alerts.push('No policy found.');
    }

    return alerts;
}

