// frontend/utils/exportUtils.js

// exportReport: Exports compliance data to a CSV file
export const exportReport = (data) => {
  const csvRows = [];
  const headers = Object.keys(data[0]);
  csvRows.push(headers.join(','));

  data.forEach(row => {
    const values = headers.map(header => JSON.stringify(row[header], replacer));
    csvRows.push(values.join(','));
  });

  const csvString = csvRows.join('\n');
  const blob = new Blob([csvString], { type: 'text/csv' });
  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.setAttribute('hidden', '');
  a.setAttribute('href', url);
  a.setAttribute('download', 'compliance_report.csv');
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
};

const replacer = (key, value) => value === null ? '' : value;

