-- This script creates the main tables required for user profiles in the FINDOM platform.

-- Create the 'users' table to store basic user information.
CREATE TABLE IF NOT EXISTS users (
    user_id SERIAL PRIMARY KEY,
    username VARCHAR(100) UNIQUE NOT NULL,
    email VARCHAR(255) UNIQUE NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Create the 'content' table to store content metadata.
CREATE TABLE IF NOT EXISTS content (
    content_id SERIAL PRIMARY KEY,
    title VARCHAR(255) NOT NULL,
    content_type VARCHAR(50) NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Create the 'user_profiles' table to store user preferences and metadata.
CREATE TABLE IF NOT EXISTS user_profiles (
    user_profile_id SERIAL PRIMARY KEY,
    user_id INT REFERENCES users(user_id) ON DELETE CASCADE,
    preferred_content_types VARCHAR(255)[],
    interaction_frequency INT DEFAULT 0,
    last_updated TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Create indexes to optimize query performance.
CREATE INDEX idx_user_id ON user_profiles(user_id);
CREATE INDEX idx_preferred_content ON user_profiles USING GIN (preferred_content_types);

