import pandas as pd
from typing import Dict, Any

def validate_data(data: Dict[str, Any]) -> pd.DataFrame:
    """
    Validates and cleans the input data, preparing it for database insertion.
    """
    # Convert JSON data to pandas DataFrame
    df = pd.DataFrame(data)
    expected_columns = ["user_id", "interaction_type", "timestamp", "details"]

    # Validate columns
    if not all(column in df.columns for column in expected_columns):
        raise ValueError(f"Data validation failed. Expected columns: {expected_columns}")

    # Drop duplicates and handle missing values
    df.drop_duplicates(inplace=True)
    df.fillna(method='ffill', inplace=True)

    return df

def aggregate_data(social_media_data: Dict, video_hosting_data: Dict) -> pd.DataFrame:
    """
    Aggregates data from different sources and returns a unified DataFrame.
    """
    # Validate and load data into DataFrames
    social_media_df = validate_data(social_media_data)
    video_hosting_df = validate_data(video_hosting_data)

    # Concatenate DataFrames
    combined_df = pd.concat([social_media_df, video_hosting_df], ignore_index=True)

    return combined_df

