import psycopg2
from psycopg2.extras import execute_batch
import pandas as pd

class DatabaseManager:
    def __init__(self, db_config: Dict[str, str]):
        self.connection = psycopg2.connect(**db_config)
        self.cursor = self.connection.cursor()

    def insert_data(self, df: pd.DataFrame, table_name: str):
        """
        Inserts data from a DataFrame into the specified PostgreSQL table.
        """
        query = f"INSERT INTO {table_name} (user_id, interaction_type, timestamp, details) VALUES (%s, %s, %s, %s)"
        execute_batch(self.cursor, query, df.values)
        self.connection.commit()

    def close(self):
        self.cursor.close()
        self.connection.close()

def main(df: pd.DataFrame):
