const express = require('express');
const bodyParser = require('body-parser');
const grpc = require('@grpc/grpc-js');
const protoLoader = require('@grpc/proto-loader');
const path = require('path');

// Load gRPC proto file
const PROTO_PATH = path.join(__dirname, 'syndication.proto');
const packageDefinition = protoLoader.loadSync(PROTO_PATH, {});
const syndicationProto = grpc.loadPackageDefinition(packageDefinition).syndication;

// Initialize Express app
const app = express();
app.use(bodyParser.json());

// Mock database to store syndication data
let syndicationDB = [];

// RESTful API to syndicate content
app.post('/api/syndicate', (req, res) => {
    const { contentId, platform } = req.body;
    if (!contentId || !platform) {
        return res.status(400).send('Missing required fields');
    }
    syndicationDB.push({ contentId, platform });
    res.status(201).send({ contentId, platform });
});

// gRPC server implementation
function syndicateContent(call, callback) {
    const { contentId, platform } = call.request;
    syndicationDB.push({ contentId, platform });
    callback(null, { success: true });
}

const server = new grpc.Server();
server.addService(syndicationProto.SyndicationService.service, { syndicateContent });
server.bindAsync('0.0.0.0:50051', grpc.ServerCredentials.createInsecure(), () => {
    server.start();
});

// Start the server
const PORT = process.env.PORT || 3001;
app.listen(PORT, () => {
    console.log(`Syndication Service running on port ${PORT}`);
});

