-- postgres_schema.sql

-- Schema for Content Metadata
CREATE TABLE content_metadata (
    content_id SERIAL PRIMARY KEY,
    title VARCHAR(255) NOT NULL,
    description TEXT,
    creator_id INT NOT NULL,
    creation_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    last_updated TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    status VARCHAR(50) CHECK (status IN ('draft', 'published', 'archived')),
    FOREIGN KEY (creator_id) REFERENCES users(user_id)
);

-- Schema for Distribution Channels
CREATE TABLE distribution_channels (
    channel_id SERIAL PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    platform_url VARCHAR(255),
    reach INT,
    engagement_rate FLOAT,
    partnership_status VARCHAR(50) CHECK (partnership_status IN ('active', 'inactive', 'pending'))
);

-- Schema for Revenue Transactions
CREATE TABLE revenue_transactions (
    transaction_id SERIAL PRIMARY KEY,
    content_id INT NOT NULL,
    channel_id INT NOT NULL,
    revenue DECIMAL(10, 2) CHECK (revenue >= 0),
    transaction_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (content_id) REFERENCES content_metadata(content_id),
    FOREIGN KEY (channel_id) REFERENCES distribution_channels(channel_id)
);

-- Indexes for Performance
CREATE INDEX idx_content_creator ON content_metadata(creator_id);
CREATE INDEX idx_transaction_content ON revenue_transactions(content_id);

-- Comments for Documentation
COMMENT ON TABLE content_metadata IS 'Stores metadata for each piece of content';
COMMENT ON TABLE distribution_channels IS 'Details about each distribution channel';
COMMENT ON TABLE revenue_transactions IS 'Records transactions related to content revenue';

