from rest_framework import viewsets, status
from rest_framework.response import Response
from .models import Contract, Reminder
from .serializers import ContractSerializer, ReminderSerializer
from django.utils import timezone
from django.core.mail import send_mail

class ContractViewSet(viewsets.ModelViewSet):
    queryset = Contract.objects.all()
    serializer_class = ContractSerializer

    def perform_create(self, serializer):
        serializer.save(creator=self.request.user)

    def update(self, request, *args, **kwargs):
        contract = self.get_object()
        if contract.status == 'executed':
            return Response({'error': 'Cannot modify executed contracts'}, status=status.HTTP_400_BAD_REQUEST)
        return super().update(request, *args, **kwargs)

class ReminderViewSet(viewsets.ModelViewSet):
    queryset = Reminder.objects.filter(remind_date__gt=timezone.now())
    serializer_class = ReminderSerializer

    def perform_create(self, serializer):
        reminder = serializer.save()
        # Schedule email reminder
