import React, { useEffect, useState } from 'react';
import * as d3 from 'd3';

function App() {
  const [data, setData] = useState(null);

  useEffect(() => {
    fetch('http://localhost:5000/api/kpis')
      .then(response => response.json())
      .then(data => setData(data))
      .catch(error => console.error('Error fetching data:', error));
  }, []);

  useEffect(() => {
    if (data) {
      renderRevenueTrends(data.revenueTrends);
      renderAudienceDemographics(data.audienceDemographics);
      renderEngagementMetrics(data.engagementMetrics);
    }
  }, [data]);

  const renderRevenueTrends = (revenueTrends) => {
    const svg = d3.select('#revenue-trends')
      .attr('width', 500)
      .attr('height', 300);

    const xScale = d3.scaleTime()
      .domain(d3.extent(revenueTrends, d => new Date(d.date)))
      .range([0, 480]);

    const yScale = d3.scaleLinear()
      .domain([0, d3.max(revenueTrends, d => d.revenue)])
      .range([280, 0]);

    const line = d3.line()
      .x(d => xScale(new Date(d.date)))
      .y(d => yScale(d.revenue));

    svg.append('path')
      .datum(revenueTrends)
      .attr('fill', 'none')
      .attr('stroke', 'steelblue')
      .attr('stroke-width', 1.5)
      .attr('d', line);
  };

  const renderAudienceDemographics = (audienceDemographics) => {
    const svg = d3.select('#audience-demographics')
      .attr('width', 500)
      .attr('height', 300);

    const xScale = d3.scaleBand()
      .domain(audienceDemographics.map(d => d.ageGroup))
      .range([0, 480])
      .padding(0.1);

    const yScale = d3.scaleLinear()
      .domain([0, 100]) // Percentage
      .range([280, 0]);

    svg.selectAll('.bar')
      .data(audienceDemographics)
      .enter().append('rect')
      .attr('class', 'bar')
      .attr('x', d => xScale(d.ageGroup))
      .attr('y', d => yScale(d.percentage))
      .attr('width', xScale.bandwidth())
      .attr('height', d => 280 - yScale(d.percentage))
      .attr('fill', 'orange');
  };

  const renderEngagementMetrics = (engagementMetrics) => {
    const svg = d3.select('#engagement-metrics')
      .attr('width', 500)
      .attr('height', 300);

    const xScale = d3.scaleBand()
      .domain(engagementMetrics.map(d => d.metric))
      .range([0, 480])
      .padding(0.1);

    const yScale = d3.scaleLinear()
      .domain([0, d3.max(engagementMetrics, d => d.count)])
      .range([280, 0]);

    svg.selectAll('.bar')
      .data(engagementMetrics)
      .enter().append('rect')
      .attr('class', 'bar')
      .attr('x', d => xScale(d.metric))
      .attr('y', d => yScale(d.count))
      .attr('width', xScale.bandwidth())
      .attr('height', d => 280 - yScale(d.count))
      .attr('fill', 'green');
  };

  return (
    <div className="App">
      <h1>FINDOM Analytics Dashboard</h1>
      <svg id="revenue-trends"></svg>
      <svg id="audience-demographics"></svg>
      <svg id="engagement-metrics"></svg>
    </div>
  );
}

