iam_client = boto3.client('iam', region_name='us-west-2')

# Create IAM Role with permissions for MediaLive and MediaPackage
def create_iam_role():
    role_name = 'MediaLiveAccessRole'
    assume_role_policy_document = {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Effect": "Allow",
                "Principal": {
                    "Service": [
                        "medialive.amazonaws.com",
                        "mediapackage.amazonaws.com"
                    ]
                },
                "Action": "sts:AssumeRole"
            }
        ]
    }

    try:
        response = iam_client.create_role(
            RoleName=role_name,
            AssumeRolePolicyDocument=json.dumps(assume_role_policy_document),
            Description='Role for accessing AWS MediaLive and MediaPackage'
        )
        role_arn = response['Role']['Arn']

        # Attach policy for full access to MediaLive and MediaPackage
        iam_client.attach_role_policy(
            RoleName=role_name,
            PolicyArn='arn:aws:iam::aws:policy/AWSMediaLiveFullAccess'
        )
        iam_client.attach_role_policy(
            RoleName=role_name,
            PolicyArn='arn:aws:iam::aws:policy/AWSMediaPackageFullAccess'
        )

        print(f"Role created with ARN: {role_arn}")
    except iam_client.exceptions.EntityAlreadyExistsException:
        print(f"Role '{role_name}' already exists.")

# Execution
if __name__ == "__main__":
    create_iam_role()

