def process_paypal_payment(data):
    """
    Process a payment using PayPal.
    :param data: A dictionary containing payment details like amount, currency.
    :return: A dictionary with transaction details or error message.
    """
    try:
        order_request = OrdersCreateRequest()
        order_request.prefer('return=representation')
        order_request.request_body({
            "intent": "CAPTURE",
            "purchase_units": [{
                "amount": {
                    "currency_code": data['currency'],
                    "value": data['amount']
                }
            }]
        })

        response = client.execute(order_request)
        return {"success": True, "order_id": response.result.id}
    except Exception as e:
        return {"success": False, "error": str(e)}

