import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

const RevenueMetricsChart = ({ data }) => {
  const svgRef = useRef();

  useEffect(() => {
    const svg = d3.select(svgRef.current);
    const width = 600;
    const height = 300;

    // Aggregate revenue data
    const revenueData = data.reduce((acc, curr) => {
      const date = new Date(curr.timestamp).toDateString();
      acc[date] = (acc[date] || 0) + curr.revenue;
      return acc;
    }, {});

    const revenueArray = Object.entries(revenueData).map(([date, revenue]) => ({ date, revenue }));

    // Set up scales
    const xScale = d3.scaleBand()
      .domain(revenueArray.map(d => d.date))
      .range([0, width])
      .padding(0.1);

    const yScale = d3.scaleLinear()
      .domain([0, d3.max(revenueArray, d => d.revenue)])
      .range([height, 0]);

    // Clear previous content
    svg.selectAll('*').remove();

    // Append bars
    svg.selectAll('.bar')
      .data(revenueArray)
      .enter()
      .append('rect')
      .attr('class', 'bar')
      .attr('x', d => xScale(d.date))
      .attr('y', d => yScale(d.revenue))
      .attr('width', xScale.bandwidth())
      .attr('height', d => height - yScale(d.revenue))
      .attr('fill', 'orange');

    // Append axes
    svg.append('g')
      .attr('transform', `translate(0, ${height})`)
      .call(d3.axisBottom(xScale));

    svg.append('g')
      .call(d3.axisLeft(yScale));

  }, [data]);

  return <svg ref={svgRef} width={600} height={300}></svg>;
};

export default RevenueMetricsChart;

