class VRDataCollector:
    def __init__(self):
        # Initialize the VR system
        openvr.init(openvr.VRApplication_Scene)
        self.vr_system = openvr.VRSystem()

    def collect_eye_tracking_data(self):
        # Collect eye-tracking data from the VR headset
        eye_data = self.vr_system.getEyeTrackingData()
        return {
            'timestamp': time.time(),
            'left_eye': eye_data.leftEye,
            'right_eye': eye_data.rightEye,
        }

    def collect_motion_sensor_data(self):
        # Collect motion sensor data from the VR controllers
        motion_data = self.vr_system.getControllerState()
        return {
            'timestamp': time.time(),
            'position': motion_data.position,
            'orientation': motion_data.orientation,
        }

    def save_data(self, data, filename='vr_data.json'):
        # Save collected data to a JSON file
        with open(filename, 'a') as f:
            json.dump(data, f)
            f.write('\n')

    def run(self, duration=60):
        # Collect data for a specified duration
        start_time = time.time()
        while time.time() - start_time < duration:
            eye_data = self.collect_eye_tracking_data()
            motion_data = self.collect_motion_sensor_data()
            self.save_data({'eye_data': eye_data, 'motion_data': motion_data})
            time.sleep(0.1)  # Collect data every 100ms

    def __del__(self):
        # Shutdown the VR system
        openvr.shutdown()

