import cv2
import numpy as np
import json

class DataProcessor:
    def __init__(self, data_file='vr_data.json'):
        self.data_file = data_file

    def load_data(self):
        with open(self.data_file, 'r') as f:
            data = [json.loads(line) for line in f]
        return data

    def process_eye_data(self, eye_data):
        # Process eye-tracking data to extract features
        left_eye = np.array(eye_data['left_eye'])
        right_eye = np.array(eye_data['right_eye'])
        eye_features = np.concatenate([left_eye, right_eye])
        return eye_features

    def process_motion_data(self, motion_data):
        # Process motion sensor data to extract features
        position = np.array(motion_data['position'])
        orientation = np.array(motion_data['orientation'])
        motion_features = np.concatenate([position, orientation])
        return motion_features

    def extract_features(self):
        data = self.load_data()
        features = []
        for entry in data:
            eye_features = self.process_eye_data(entry['eye_data'])
            motion_features = self.process_motion_data(entry['motion_data'])
            features.append(np.concatenate([eye_features, motion_features]))
        return np.array(features)

    def normalize_features(self, features):
        # Normalize features for machine learning models
        mean = np.mean(features, axis=0)
        std = np.std(features, axis=0)
        normalized_features = (features - mean) / std
        return normalized_features


