// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/// @title RevenueSharing - A smart contract for distributing revenue among creators.
contract RevenueSharing {
    // Mapping to store creator addresses and their revenue shares.
    mapping(address => uint256) public shares;

    // Total shares allocated
    uint256 public totalShares;

    // Owner of the contract
    address public owner;

    // Events for logging
    event PaymentReceived(address from, uint256 amount);
    event RevenueDistributed(uint256 amount);

    /// @notice Constructor to set the initial owner
    constructor() {
        owner = msg.sender;
    }

    /// @notice Modifier to restrict actions to the contract owner
    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this function");
        _;
    }

    /// @notice Function to set the share for a creator
    /// @param creator The address of the creator
    /// @param share The share percentage of the creator
    function setShare(address creator, uint256 share) external onlyOwner {
        require(creator != address(0), "Invalid address");
        require(share > 0 && share <= 100, "Share must be between 1 and 100");

        if (shares[creator] == 0) {
            totalShares += share;
        } else {
            totalShares = totalShares - shares[creator] + share;
        }

        require(totalShares <= 100, "Total shares exceed 100%");

        shares[creator] = share;
    }

    /// @notice Fallback function to receive payments
    receive() external payable {
        emit PaymentReceived(msg.sender, msg.value);
    }

    /// @notice Distribute revenue to all creators based on their shares
    function distributeRevenue() external {
        uint256 totalBalance = address(this).balance;
        require(totalBalance > 0, "No funds to distribute");

        for (address creator in creators) {
            uint256 payment = (totalBalance * shares[creator]) / 100;
            require(payment > 0, "Payment calculation error");
            payable(creator).transfer(payment);
        }

        emit RevenueDistributed(totalBalance);
    }
}

