    recipient = "compliance@findom.com"
    subject = f"Compliance Alert for Contract {contract_id}"
    body = f"Compliance issue detected: {issue}. Contract end date: {end_date}."

    msg = MIMEText(body)
    msg['Subject'] = subject
    msg['From'] = sender
    msg['To'] = recipient

    # Send email
    with smtplib.SMTP('localhost') as server:
        server.sendmail(sender, [recipient], msg.as_string())
        print(f"Email sent for contract {contract_id}")

