package findom_analytics.flink_job;

import org.apache.flink.api.common.functions.MapFunction;
import org.apache.flink.streaming.api.datastream.DataStream;
import org.apache.flink.streaming.api.environment.StreamExecutionEnvironment;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaConsumer;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaProducer;
import org.apache.flink.api.common.serialization.SimpleStringSchema;
import org.apache.flink.api.common.typeinfo.TypeInformation;
import org.apache.flink.shaded.jackson2.com.fasterxml.jackson.databind.ObjectMapper;
import org.apache.flink.shaded.jackson2.com.fasterxml.jackson.databind.JsonNode;

import java.util.Properties;

public class DataAggregationJob {

    public static void main(String[] args) throws Exception {
        // Set up the streaming execution environment
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Configure Kafka consumer properties
        Properties properties = new Properties();
        properties.setProperty("bootstrap.servers", "localhost:9092");
        properties.setProperty("group.id", "findom-group");

        // Create a Kafka consumer for the input topic
        FlinkKafkaConsumer<String> consumer = new FlinkKafkaConsumer<>(
                "findom-input-topic",
                new SimpleStringSchema(),
                properties
        );

        // Define data stream from the consumer
        DataStream<String> inputStream = env.addSource(consumer);

        // Transform input data into a more structured form
        DataStream<JsonNode> processedStream = inputStream.map(new MapFunction<String, JsonNode>() {
            private static final long serialVersionUID = 1L;
            private final ObjectMapper objectMapper = new ObjectMapper();

            @Override
            public JsonNode map(String value) throws Exception {
                // Parse JSON and extract relevant fields
                return objectMapper.readTree(value);
            }
        }).returns(TypeInformation.of(JsonNode.class));

        // Transform processed data into output format and send to output topic
        DataStream<String> outputStream = processedStream.map(new MapFunction<JsonNode, String>() {
            private static final long serialVersionUID = 1L;

            @Override
            public String map(JsonNode jsonNode) {
                // Extract and format data as required
                String licensingPerformance = jsonNode.get("licensingPerformance").asText();
                return licensingPerformance;
            }
        });

        // Configure Kafka producer properties
        FlinkKafkaProducer<String> producer = new FlinkKafkaProducer<>(
                "findom-output-topic",
                new SimpleStringSchema(),
                properties
        );

        // Add sink to send processed data to a Kafka topic
        outputStream.addSink(producer);

        // Execute the Flink job
        env.execute("Findom Data Aggregation Job");
    }
}

