import torch
import torch.nn as nn
import torch.optim as optim
import json
from kafka import KafkaConsumer, KafkaProducer

class LicensingPerformanceModel(nn.Module):
    def __init__(self):
        super(LicensingPerformanceModel, self).__init__()
        self.layer1 = nn.Linear(10, 50)
        self.layer2 = nn.Linear(50, 20)
        self.output_layer = nn.Linear(20, 1)

    def forward(self, x):
        x = torch.relu(self.layer1(x))
        x = torch.relu(self.layer2(x))
        x = self.output_layer(x)
        return x

def train_model(data_stream):
    model = LicensingPerformanceModel()
    criterion = nn.MSELoss()
    optimizer = optim.Adam(model.parameters(), lr=0.001)

    for data_point in data_stream:
        # Assuming data_point is a dictionary with features and target
        features = torch.tensor(data_point['features'], dtype=torch.float32)
        target = torch.tensor(data_point['target'], dtype=torch.float32)

        optimizer.zero_grad()
        output = model(features)
        loss = criterion(output, target)
        loss.backward()
        optimizer.step()

    return model

def run_inference(model, data):
    with torch.no_grad():
        features = torch.tensor(data['features'], dtype=torch.float32)
        prediction = model(features)
        return prediction.item()

def main():
    # Kafka consumer for reading processed data
    consumer = KafkaConsumer(
        'findom-output-topic',
        bootstrap_servers='localhost:9092',
        value_deserializer=lambda x: json.loads(x.decode('utf-8'))
    )

    # Kafka producer to send results to another topic
    producer = KafkaProducer(
        bootstrap_servers='localhost:9092',
        value_serializer=lambda x: json.dumps(x).encode('utf-8')
    )

    # Train model with initial data
    model = LicensingPerformanceModel()
    initial_data = [{"features": [0.1] * 10, "target": 0.5}] * 100  # Replace with real data
    model = train_model(initial_data)

    # Process incoming data and run inference
    for message in consumer:
        data = message.value
        prediction = run_inference(model, data)
        producer.send('findom-prediction-topic', {'prediction': prediction})

if __name__ == "__main__":
    main()

