// middleware/authMiddleware.js
const jwt = require('jsonwebtoken');

// Middleware to check authentication and authorization
const authMiddleware = (requiredRole) => {
  return (req, res, next) => {
    const authHeader = req.headers.authorization;
    if (!authHeader) return res.status(401).json({ error: 'Authorization header missing' });

    const token = authHeader.split(' ')[1];
    jwt.verify(token, 'secretKey', (err, decoded) => {
      if (err) return res.status(403).json({ error: 'Failed to authenticate token' });

      if (requiredRole && decoded.role !== requiredRole) {
        return res.status(403).json({ error: 'Insufficient permissions' });
      }

      req.user = decoded;
      next();
    });
  };
};

module.exports = authMiddleware;

// EXPLANATION:
// - The authMiddleware function is a higher-order function that takes a required role as an argument.
// - It verifies the JWT token from the authorization header and checks if the user has the required role.
// - If the user is not authenticated or lacks the required role, it returns a 403 Forbidden response.

