      .attr('width', 800)
      .attr('height', 400);

    // Clear previous content
    svg.selectAll('*').remove();

    // Create a bar chart
    svg.selectAll('rect')
      .data(data)
      .enter()
      .append('rect')
      .attr('x', (d, i) => i * 50)
      .attr('y', d => 400 - d.revenueImpact)
      .attr('width', 40)
      .attr('height', d => d.revenueImpact)
      .attr('fill', 'teal');

    // Add labels
    svg.selectAll('text')
      .data(data)
      .enter()
      .append('text')
      .text(d => d.audienceEngagement)
      .attr('x', (d, i) => i * 50 + 20)
      .attr('y', d => 400 - d.revenueImpact - 10)
      .attr('text-anchor', 'middle');
  }, [data]);

  return <svg ref={chartRef}></svg>;
};

export default Chart;

