import React, { useState, useEffect } from 'react';
import ChartComponent from './ChartComponent';
import RoleBasedAccessControl from './RoleBasedAccessControl';
import { fetchSponsorshipAnalytics } from '../services/analyticsService';

const Dashboard = () => {
  const [analyticsData, setAnalyticsData] = useState([]);
  const [userRole, setUserRole] = useState('viewer'); // Example role

  useEffect(() => {
    const fetchData = async () => {
      try {
        const data = await fetchSponsorshipAnalytics();
        setAnalyticsData(data);
      } catch (error) {
        console.error('Error fetching analytics data:', error);
      }
    };
    fetchData();
  }, []);

  return (
    <div className="dashboard">
      <RoleBasedAccessControl userRole={userRole}>
        <h1>Sponsorship Analytics Dashboard</h1>
        {analyticsData.map((metric, index) => (
          <ChartComponent key={index} data={metric.data} type={metric.type} options={metric.options} />
        ))}
      </RoleBasedAccessControl>
    </div>
  );
};

export default Dashboard;

